After updating the badge text, set an `aria-live="polite"` region (or reuse the existing live region) to announce the count. Example:  

```js
function _updateCountBadge(count) {
  if (!_countBadge) return;
  _countBadge.textContent = String(count);
  _countBadge.setAttribute('aria-label', `${count} product${count!==1?'s':''}`);
  liveRegion.announce(`${count} product${count!==1?'s':''} found`); // ← added
}
```

